mapper.insert:
INSERT INTO sys_login_log (
    id, username, ip_address, user_agent, status, message, login_time,
    created_by, created_time, updated_by, updated_time
) VALUES (
    #{id}, #{username}, #{ipAddress}, #{userAgent}, #{status}, #{message}, #{loginTime},
    #{createdBy}, #{createdTime}, #{updatedBy}, #{updatedTime}
)

mapper.select:
SELECT id, username, ip_address, user_agent, status, message, login_time FROM sys_login_log WHERE deleted = FALSE
AND username LIKE CONCAT('%', #{username}, '%')
AND status = #{status}
AND login_time >= CAST(#{startTime} AS TIMESTAMPTZ)
AND login_time < CAST(#{endTime} AS TIMESTAMPTZ) + INTERVAL '1 day'
ORDER BY login_time DESC LIMIT #{pageSize} OFFSET #{offset}
